It will be easier and cleaner to define columns through breakpoints like: `@include make-cols(12,8,4,12,12)` with default "12". Bellow my custom mixin for that (added half of container margin - for my own use). Could be better and shorter, of course.

```
@mixin make-cols($xxl:12, $xl:12, $lg:12, $md:12, $sm:12, $xs:12){
    $containers: (
        xs: 100%,
        sm: 540px,
        md: 720px,
        lg: 960px,
        xl: 1140px,
        xxl: 1320px
    );

    $padding: -12px;

    width: 100%;

    @if $xs != 0 {
        @include media-breakpoint-up(xs){
            @if $xs == f {
                width: 100vw;
            } @else {
                width: calc( ( ((100vw - (100vw - 100%)) - #{map-get($containers, xs)}) / 2 ) + ( (#{map-get($containers, xs)} * (#{$xs} / 12))) + #{$padding});
            }
        }
    }

    @if $sm != 0 {
        @include media-breakpoint-up(sm){
            @if $sm == f {
                width: 100vw;
            } @else {
                width: calc( ( ((100vw - (100vw - 100%)) - #{map-get($containers, sm)}) / 2 ) + ( (#{map-get($containers, sm)} * (#{$sm} / 12))) + #{$padding});
            }
        }
    }

    @if $md != 0 {
        @include media-breakpoint-up(md){
            @if $md == f {
                width: 100vw;
            } @else {
                width: calc( ( ((100vw - (100vw - 100%)) - #{map-get($containers, md)}) / 2 ) + ( (#{map-get($containers, md)} * (#{$md} / 12))) + #{$padding});
            }
        }
    }

    @if $lg != 0 {
        @include media-breakpoint-up(lg){
            @if $lg == f {
                width: 100vw;
            } @else {
                width: calc( ( ((100vw - (100vw - 100%)) - #{map-get($containers, lg)}) / 2 ) + ( (#{map-get($containers, lg)} * (#{$lg} / 12))) + #{$padding});
            }
        }
    }

    @if $xl != 0 {    
        @include media-breakpoint-up(xl){
            @if $xl == f {
                width: 100vw;
            } @else {
                width: calc( ( ((100vw - (100vw - 100%)) - #{map-get($containers, xl)}) / 2 ) + ( (#{map-get($containers, xl)} * (#{$xl} / 12))) + #{$padding});
            }
        }
    }

    @if $xxl != 0 {    
        @include media-breakpoint-up(xxl){
            @if $xxl == f {
                width: 100vw;
            } @else {
                width: calc( ( ((100vw - (100vw - 100%)) - #{map-get($containers, xxl)}) / 2 ) + ( (#{map-get($containers, xxl)} * (#{$xxl} / 12))) + #{$padding});
            }
        }
    }
}


```

